  const { chromium } = await import('playwright');
  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({ viewport: { width: 1440, height: 900 }, deviceScaleFactor: 1 });
  const page = await context.newPage();
  const messages = [];
  page.on('console', (msg) => messages.push(`${msg.type()}: ${msg.text()}`));
  page.on('pageerror', (error) => messages.push(`pageerror: ${error.message}`));
  await page.goto('http://127.0.0.1:5173/', { waitUntil: 'networkidle' });
  await page.evaluate(() => {
    const loader = document.getElementById('loader');
    loader?.classList.remove('done');
    if (loader) loader.style.opacity = '1';
  });
  await page.waitForSelector('.loader-marvin');
  const info = await page.locator('.loader-marvin').evaluate((img) => {
    const rect = img.getBoundingClientRect();
    const computed = getComputedStyle(img);
    return {
      src: img.getAttribute('src'),
      complete: img.complete,
      naturalWidth: img.naturalWidth,
      naturalHeight: img.naturalHeight,
      renderedWidth: Math.round(rect.width),
      renderedHeight: Math.round(rect.height),
      computedWidth: computed.width,
      visible: rect.width > 0 && rect.height > 0 && computed.display !== 'none' && computed.visibility !== 'hidden',
    };
  });
  const png = await page.screenshot({ fullPage: true });
  await browser.close();
  await nodeRepl.emitImage({ bytes: png, mimeType: 'image/png' });
  nodeRepl.write(JSON.stringify({ info, messages }, null, 2));
}"}

