  const { chromium } = await import('playwright');
  const browser = await chromium.launch({
    headless: true,
    executablePath: '/Applications/Google Chrome.app/Contents/MacOS/Google Chrome',
  });
  const page = await browser.newPage({ viewport: { width: 1200, height: 800 } });
  const responses = [];
  page.on('response', (response) => {
    if (response.url().includes('slack-entire-marvin')) responses.push({ url: response.url(), status: response.status() });
  });
  await page.goto('http://127.0.0.1:5173/', { waitUntil: 'networkidle' });
  await page.evaluate(() => {
    const loader = document.getElementById('loader');
    loader?.classList.remove('done');
    if (loader) loader.style.opacity = '1';
  });
  const info = await page.locator('.loader-marvin').evaluate(async (img) => {
    await img.decode().catch(() => {});
    const canvas = document.createElement('canvas');
    canvas.width = img.naturalWidth;
    canvas.height = img.naturalHeight;
    const ctx = canvas.getContext('2d');
    ctx.fillStyle = 'rgb(22, 64, 88)';
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    ctx.drawImage(img, 0, 0);
    const pixel = (x, y) => Array.from(ctx.getImageData(x, y, 1, 1).data);
    const rect = img.getBoundingClientRect();
    return {
      src: img.getAttribute('src'),
      complete: img.complete,
      naturalWidth: img.naturalWidth,
      naturalHeight: img.naturalHeight,
      renderedWidth: Math.round(rect.width),
      topLeft: pixel(0, 0),
      topRight: pixel(canvas.width - 1, 0),
      bottomLeft: pixel(0, canvas.height - 1),
      center: pixel(Math.floor(canvas.width / 2), Math.floor(canvas.height / 2)),
    };
  });
  await browser.close();
  nodeRepl.write(JSON.stringify({ info, responses }, null, 2));
}"}

