arguments.code:
{
  const { chromium } = await import('playwright');
  const browser = await chromium.launch({
    headless: true,
    executablePath: '/Applications/Google Chrome.app/Contents/MacOS/Google Chrome',
  });
  const page = await browser.newPage({ viewport: { width: 1440, height: 900 } });
  await page.goto('http://127.0.0.1:5173/', { waitUntil: 'networkidle' });
  await page.evaluate(() => {
    const loader = document.getElementById('loader');
    loader?.classList.remove('done');
    if (loader) loader.style.opacity = '1';
  });
  await page.waitForTimeout(450);
  const info = await page.evaluate(() => {
    const loader = document.getElementById('loader');
    const img = document.querySelector('.loader-marvin');
    const ring = document.querySelector('.loader-ring');
    const text = document.querySelector('.loader-text');
    const rect = img.getBoundingClientRect();
    return {
      hasRing: !!ring,
      loaderBackground: getComputedStyle(loader).backgroundColor,
      imgSrc: img.getAttribute('src'),
      imgComplete: img.complete,
      renderedWidth: Math.round(rect.width),
      renderedHeight: Math.round(rect.height),
      text: text?.textContent,
    };
  });
  const png = await page.screenshot({ fullPage: true });
  await browser.close();
  await nodeRepl.emitImage({ bytes: png, mimeType: 'image/png' });
  nodeRepl.write(JSON.stringify(info, null, 2));
}

